import "jsr:@supabase/functions-js/edge-runtime.d.ts";
import { createClient } from "jsr:@supabase/supabase-js@2";

import { mapPayPlusChargeToCheckRow } from "./charge-sync.ts";
import { fetchActiveRecurringPayments, fetchRecurringCharges } from "./payplus-client.ts";
import { mapPayPlusRecurringToClient } from "./mapper.ts";
import type { RecurringClientUpsertRow, SyncError, SyncResult } from "./types.ts";

const corsHeaders = {
  "Access-Control-Allow-Origin": "*",
  "Access-Control-Allow-Headers":
    "authorization, x-client-info, apikey, content-type, x-cron-secret",
};

const UPSERT_BATCH_SIZE = 100;

Deno.serve(async (req: Request) => {
  if (req.method === "OPTIONS") {
    return new Response("ok", { headers: corsHeaders });
  }

  if (req.method !== "POST" && req.method !== "GET") {
    return jsonResponse({ error: "Method not allowed" }, 405);
  }

  try {
    assertAuthorized(req);

    const payplusConfig = getPayPlusConfig();
    const supabase = createServiceRoleClient();

    const recurringPayments = await fetchActiveRecurringPayments(payplusConfig);

    const rows: RecurringClientUpsertRow[] = [];
    const errors: SyncError[] = [];

    for (const item of recurringPayments) {
      const { row, error } = mapPayPlusRecurringToClient(item);
      if (error) {
        errors.push(error);
        continue;
      }
      if (row) rows.push(row);
    }

    let createdCount = 0;
    let updatedCount = 0;

    if (rows.length > 0) {
      const recurringUids = rows.map((row) => row.payplus_recurring_uid);
      const existingUids = await loadExistingRecurringUids(supabase, recurringUids);

      for (let index = 0; index < rows.length; index += UPSERT_BATCH_SIZE) {
        const batch = rows.slice(index, index + UPSERT_BATCH_SIZE);

        const { error: upsertError } = await supabase
          .from("recurring_clients")
          .upsert(batch, { onConflict: "payplus_recurring_uid" });

        if (upsertError) {
          errors.push({ message: `Database upsert failed: ${upsertError.message}` });
          continue;
        }

        for (const row of batch) {
          if (existingUids.has(row.payplus_recurring_uid)) {
            updatedCount += 1;
          } else {
            createdCount += 1;
            existingUids.add(row.payplus_recurring_uid);
          }
        }
      }
    }

    const chargesSyncedCount = await syncAllRecurringCharges(
      supabase,
      payplusConfig,
      errors,
    );

    return jsonResponse({
      synced_count: createdCount + updatedCount,
      created_count: createdCount,
      updated_count: updatedCount,
      charges_synced_count: chargesSyncedCount,
      errors,
    } satisfies SyncResult);
  } catch (error) {
    const message = error instanceof Error
      ? error.message
      : "Unexpected sync error";

    console.error("sync-payplus-recurring-customers failed:", message);

    return jsonResponse({
      synced_count: 0,
      created_count: 0,
      updated_count: 0,
      charges_synced_count: 0,
      errors: [{ message }],
    } satisfies SyncResult, error instanceof UnauthorizedError ? 401 : 500);
  }
});

class UnauthorizedError extends Error {
  constructor() {
    super("Unauthorized");
    this.name = "UnauthorizedError";
  }
}

function assertAuthorized(req: Request) {
  const cronSecret = Deno.env.get("PAYPLUS_CRON_SECRET");
  const headerSecret = req.headers.get("x-cron-secret");

  if (cronSecret && headerSecret && headerSecret === cronSecret) {
    return;
  }

  const authHeader = req.headers.get("Authorization");
  if (authHeader?.startsWith("Bearer ")) {
    return;
  }

  throw new UnauthorizedError();
}

async function syncAllRecurringCharges(
  supabase: ReturnType<typeof createClient>,
  payplusConfig: ReturnType<typeof getPayPlusConfig>,
  errors: SyncError[],
): Promise<number> {
  const { data: clients, error } = await supabase
    .from("recurring_clients")
    .select("id, payplus_recurring_uid")
    .not("payplus_recurring_uid", "is", null);

  if (error) {
    errors.push({ message: `Failed to load recurring clients: ${error.message}` });
    return 0;
  }

  let synced = 0;

  for (const client of clients ?? []) {
    const recurringUid = client.payplus_recurring_uid;
    if (!recurringUid) continue;

    try {
      const charges = await fetchRecurringCharges(payplusConfig, recurringUid);
      const chargeRows = charges
        .map((charge) =>
          mapPayPlusChargeToCheckRow(charge, client.id, recurringUid)
        )
        .filter((row): row is NonNullable<typeof row> => row !== null);

      if (chargeRows.length === 0) continue;

      const { error: upsertError } = await supabase
        .from("recurring_charge_checks")
        .upsert(chargeRows, { onConflict: "payplus_charge_uid" });

      if (upsertError) {
        errors.push({
          payplus_recurring_uid: recurringUid,
          message: `Charge upsert failed: ${upsertError.message}`,
        });
        continue;
      }

      synced += chargeRows.length;
      await updateClientChargeSummary(supabase, client.id, chargeRows);
    } catch (chargeError) {
      errors.push({
        payplus_recurring_uid: recurringUid,
        message: chargeError instanceof Error
          ? chargeError.message
          : "Charge sync failed",
      });
    }
  }

  return synced;
}

async function updateClientChargeSummary(
  supabase: ReturnType<typeof createClient>,
  clientId: string,
  chargeRows: Array<{
    status: string;
    failure_reason: string | null;
    charged_at: string | null;
  }>,
) {
  const successRows = chargeRows
    .filter((row) => row.status === "success")
    .sort((a, b) => (b.charged_at ?? "").localeCompare(a.charged_at ?? ""));

  const failedRows = chargeRows
    .filter((row) => row.status === "failed")
    .sort((a, b) => (b.charged_at ?? "").localeCompare(a.charged_at ?? ""));

  const latestSuccess = successRows[0];
  const latestFailed = failedRows[0];

  const now = new Date();
  const monthKey = `${now.getFullYear()}-${String(now.getMonth() + 1).padStart(2, "0")}`;
  const monthSuccess = chargeRows.some(
    (row) => row.status === "success" && row.charged_at?.startsWith(monthKey),
  );
  const monthFailed = chargeRows.some(
    (row) => row.status === "failed" && row.charged_at?.startsWith(monthKey),
  );

  let currentMonthStatus = "unknown";
  if (monthFailed) currentMonthStatus = "failed";
  else if (monthSuccess) currentMonthStatus = "charged";

  await supabase
    .from("recurring_clients")
    .update({
      current_month_status: currentMonthStatus,
      last_successful_charge_at: latestSuccess?.charged_at ?? null,
      last_failed_charge_at: latestFailed?.charged_at ?? null,
      last_failure_reason: latestFailed?.failure_reason ?? null,
    })
    .eq("id", clientId);
}

function getPayPlusConfig() {
  const apiKey = Deno.env.get("PAYPLUS_API_KEY");
  const secretKey = Deno.env.get("PAYPLUS_SECRET_KEY");
  const terminalUid = Deno.env.get("PAYPLUS_TERMINAL_UID");
  const baseUrl = Deno.env.get("PAYPLUS_API_BASE_URL");

  const missing: string[] = [];
  if (!apiKey) missing.push("PAYPLUS_API_KEY");
  if (!secretKey) missing.push("PAYPLUS_SECRET_KEY");
  if (!terminalUid) missing.push("PAYPLUS_TERMINAL_UID");
  if (!baseUrl) missing.push("PAYPLUS_API_BASE_URL");

  if (missing.length > 0) {
    throw new Error(`Missing required secrets: ${missing.join(", ")}`);
  }

  return {
    apiKey: apiKey!,
    secretKey: secretKey!,
    terminalUid: terminalUid!,
    baseUrl: baseUrl!,
  };
}

function createServiceRoleClient() {
  const supabaseUrl = Deno.env.get("SUPABASE_URL");
  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");

  if (!supabaseUrl || !serviceRoleKey) {
    throw new Error("Missing Supabase service role configuration");
  }

  return createClient(supabaseUrl, serviceRoleKey, {
    auth: {
      autoRefreshToken: false,
      persistSession: false,
    },
  });
}

async function loadExistingRecurringUids(
  supabase: ReturnType<typeof createClient>,
  recurringUids: string[],
): Promise<Set<string>> {
  const existing = new Set<string>();

  for (let index = 0; index < recurringUids.length; index += UPSERT_BATCH_SIZE) {
    const batch = recurringUids.slice(index, index + UPSERT_BATCH_SIZE);

    const { data, error } = await supabase
      .from("recurring_clients")
      .select("payplus_recurring_uid")
      .in("payplus_recurring_uid", batch);

    if (error) {
      throw new Error(`Failed to load existing clients: ${error.message}`);
    }

    for (const row of data ?? []) {
      if (row.payplus_recurring_uid) {
        existing.add(row.payplus_recurring_uid);
      }
    }
  }

  return existing;
}

function jsonResponse(body: unknown, status = 200) {
  return new Response(JSON.stringify(body), {
    status,
    headers: {
      ...corsHeaders,
      "Content-Type": "application/json",
      Connection: "keep-alive",
    },
  });
}

import type {
  PayPlusRecurringChargeListResponse,
  PayPlusRecurringListResponse,
  PayPlusRecurringPayment,
  PayPlusRecurringCharge,
} from "./types.ts";

const PAGE_SIZE = 500;

interface PayPlusConfig {
  apiKey: string;
  secretKey: string;
  terminalUid: string;
  baseUrl: string;
}

export async function fetchActiveRecurringPayments(
  config: PayPlusConfig,
): Promise<PayPlusRecurringPayment[]> {
  const allItems: PayPlusRecurringPayment[] = [];
  let skip = 0;
  let totalCount: number | null = null;

  while (true) {
    const url = buildPayPlusUrl(config.baseUrl, "RecurringPayments/View", {
      terminal_uid: config.terminalUid,
      skip: String(skip),
      take: String(PAGE_SIZE),
    });

    const response = await fetch(url, {
      method: "GET",
      headers: {
        "api-key": config.apiKey,
        "secret-key": config.secretKey,
        Accept: "application/json",
      },
    });

    const body = await parseJsonResponse(response);

    if (!response.ok) {
      const message = extractPayPlusErrorMessage(body) ??
        `PayPlus request failed with status ${response.status}`;
      throw new Error(message);
    }

    const payload = body as PayPlusRecurringListResponse;
    const pageItems = Array.isArray(payload.data) ? payload.data : [];

    if (totalCount === null && typeof payload.count === "number") {
      totalCount = payload.count;
    }

    allItems.push(...pageItems);

    if (pageItems.length < PAGE_SIZE) break;
    if (totalCount !== null && skip + PAGE_SIZE >= totalCount) break;

    skip += PAGE_SIZE;
  }

  return allItems.filter((item) => {
    const valid = item.valid;
    if (typeof valid === "boolean") return valid;
    if (typeof valid === "string") {
      return valid.toLowerCase() === "true" || valid === "1";
    }
    if (typeof valid === "number") return valid === 1;
    return false;
  });
}

export async function fetchRecurringCharges(
  config: PayPlusConfig,
  recurringUid: string,
): Promise<PayPlusRecurringCharge[]> {
  const path = `RecurringPayments/${encodeURIComponent(recurringUid)}/ViewRecurringCharge`;
  const url = buildPayPlusUrl(config.baseUrl, path, {
    terminal_uid: config.terminalUid,
    skip: "0",
    take: "500",
  });

  const response = await fetch(url, {
    method: "GET",
    headers: {
      "api-key": config.apiKey,
      "secret-key": config.secretKey,
      Accept: "application/json",
    },
  });

  const body = await parseJsonResponse(response);

  if (!response.ok) {
    const message = extractPayPlusErrorMessage(body) ??
      `PayPlus charges request failed with status ${response.status}`;
    throw new Error(message);
  }

  const payload = body as PayPlusRecurringChargeListResponse;
  return Array.isArray(payload.data) ? payload.data : [];
}

function buildPayPlusUrl(
  baseUrl: string,
  path: string,
  params: Record<string, string>,
): string {
  const normalizedBase = baseUrl.replace(/\/+$/, "");
  const normalizedPath = path.replace(/^\/+/, "");
  const url = new URL(`${normalizedBase}/${normalizedPath}`);

  for (const [key, value] of Object.entries(params)) {
    url.searchParams.set(key, value);
  }

  return url.toString();
}

async function parseJsonResponse(response: Response): Promise<unknown> {
  const text = await response.text();
  if (!text) return {};

  try {
    return JSON.parse(text);
  } catch {
    return { message: text.slice(0, 500) };
  }
}

function extractPayPlusErrorMessage(body: unknown): string | null {
  if (!body || typeof body !== "object") return null;

  const record = body as Record<string, unknown>;
  const candidates = [record.message, record.error, record.description];

  for (const candidate of candidates) {
    if (typeof candidate === "string" && candidate.trim()) {
      return candidate.trim();
    }
  }

  return null;
}

export interface SyncResult {
  synced_count: number;
  created_count: number;
  updated_count: number;
  charges_synced_count: number;
  errors: SyncError[];
}

export interface SyncError {
  payplus_recurring_uid?: string;
  message: string;
}

export interface PayPlusRecurringListResponse {
  data?: PayPlusRecurringPayment[];
  pages?: number;
  count?: number;
}

export interface PayPlusRecurringChargeListResponse {
  data?: PayPlusRecurringCharge[];
  count?: number;
}

export type PayPlusRecurringCharge = Record<string, unknown>;

export type PayPlusRecurringPayment = Record<string, unknown>;

export interface RecurringClientUpsertRow {
  payplus_customer_uid: string | null;
  payplus_recurring_uid: string;
  customer_name: string;
  customer_email: string | null;
  customer_phone: string | null;
  website_url: string | null;
  monthly_amount: number;
  currency: string;
  billing_day: number | null;
  next_billing_date: string | null;
  recurring_status: string;
  source: string;
  raw_payplus_data: Record<string, unknown>;
}

import type { PayPlusRecurringCharge } from "./types.ts";

const SENSITIVE_KEYS = new Set([
  "card_token",
  "cc_number",
  "cc_expiration",
  "cvv",
  "card_number",
]);

export interface ChargeCheckUpsertRow {
  recurring_client_id: string;
  payplus_transaction_uid: string | null;
  payplus_recurring_uid: string;
  payplus_charge_uid: string;
  check_month: string;
  amount: number;
  currency: string;
  status: string;
  failure_reason: string | null;
  charged_at: string | null;
  raw_payplus_data: Record<string, unknown>;
}

export function mapPayPlusChargeToCheckRow(
  charge: PayPlusRecurringCharge,
  recurringClientId: string,
  payplusRecurringUid: string,
): ChargeCheckUpsertRow | null {
  const chargeUid = pickString(charge, "uid");
  if (!chargeUid) return null;

  const chargeDate = parsePayPlusDate(
    pickString(charge, "charge_execution_date", "charge_date"),
  );
  const checkMonth = chargeDate ? chargeDate.slice(0, 7) : new Date().toISOString().slice(0, 7);

  const statusRaw = (pickString(charge, "status") ?? "unknown").toLowerCase();
  const errorCode = pickString(charge, "errorCode", "error_code");
  const isFailed =
    statusRaw === "failed" ||
    statusRaw === "failure" ||
    statusRaw === "error" ||
    statusRaw === "declined" ||
    Boolean(errorCode);

  const status = isFailed ? "failed" : statusRaw === "success" ? "success" : statusRaw;

  const transactionId = pickNumber(charge, "transaction_id");

  return {
    recurring_client_id: recurringClientId,
    payplus_transaction_uid: transactionId ? String(transactionId) : null,
    payplus_recurring_uid: payplusRecurringUid,
    payplus_charge_uid: chargeUid,
    check_month: checkMonth,
    amount: pickNumber(charge, "amount") ?? 0,
    currency: pickString(charge, "currency", "currency_code") ?? "ILS",
    status,
    failure_reason: errorCode ?? (isFailed ? pickString(charge, "message") : null),
    charged_at: chargeDate ? `${chargeDate}T12:00:00.000Z` : null,
    raw_payplus_data: sanitizeCharge(charge),
  };
}

function sanitizeCharge(raw: PayPlusRecurringCharge): Record<string, unknown> {
  const sanitized: Record<string, unknown> = {};
  for (const [key, value] of Object.entries(raw)) {
    if (!SENSITIVE_KEYS.has(key.toLowerCase())) {
      sanitized[key] = value;
    }
  }
  return sanitized;
}

function pickString(obj: PayPlusRecurringCharge, ...keys: string[]): string | null {
  for (const key of keys) {
    const value = obj[key];
    if (typeof value === "string" && value.trim()) return value.trim();
  }
  return null;
}

function pickNumber(obj: PayPlusRecurringCharge, ...keys: string[]): number | null {
  for (const key of keys) {
    const value = obj[key];
    if (typeof value === "number" && Number.isFinite(value)) return value;
    if (typeof value === "string" && value.trim()) {
      const parsed = Number(value);
      if (Number.isFinite(parsed)) return parsed;
    }
  }
  return null;
}

function parsePayPlusDate(value: string | null): string | null {
  if (!value) return null;
  if (/^\d{4}-\d{2}-\d{2}$/.test(value)) return value;
  const match = value.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if (match) return `${match[3]}-${match[2]}-${match[1]}`;
  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return null;
  return parsed.toISOString().slice(0, 10);
}

import type {
  PayPlusRecurringPayment,
  RecurringClientUpsertRow,
  SyncError,
} from "./types.ts";

const SENSITIVE_KEYS = new Set([
  "cc_number",
  "cc_expiration",
  "cvv",
  "card_number",
  "card_expiration",
  "credit_card_number",
  "credit_card_expiration",
]);

export function isActiveRecurringPayment(item: PayPlusRecurringPayment): boolean {
  const valid = item.valid;
  if (typeof valid === "boolean") return valid;
  if (typeof valid === "string") {
    return valid.toLowerCase() === "true" || valid === "1";
  }
  if (typeof valid === "number") return valid === 1;
  return false;
}

export function sanitizePayPlusData(
  raw: PayPlusRecurringPayment,
): Record<string, unknown> {
  const sanitized: Record<string, unknown> = {};

  for (const [key, value] of Object.entries(raw)) {
    if (!SENSITIVE_KEYS.has(key.toLowerCase())) {
      sanitized[key] = value;
    }
  }

  return sanitized;
}

export function mapPayPlusRecurringToClient(
  item: PayPlusRecurringPayment,
): { row: RecurringClientUpsertRow | null; error: SyncError | null } {
  const recurringUid = pickString(item, "uid", "recurring_uid", "recurring_payment_uid");

  if (!recurringUid) {
    return {
      row: null,
      error: { message: "Missing recurring payment uid in PayPlus item" },
    };
  }

  const amount = pickNumber(
    item,
    "each_payment_amount",
    "amount",
    "monthly_amount",
    "payment_amount",
  );

  if (amount === null || amount < 0) {
    return {
      row: null,
      error: {
        payplus_recurring_uid: recurringUid,
        message: "Missing or invalid payment amount",
      },
    };
  }

  const customerName =
    pickString(item, "customer_name", "name", "client_name") ?? "???????? ?????? ????";

  const nextBillingDate = pickDateString(
    item,
    "next_charge_date",
    "next_billing_date",
    "first_charge_date",
    "start_date",
  );

  const billingDaySource = pickDateString(
    item,
    "first_charge_date",
    "start_date",
    "next_charge_date",
  );

  return {
    row: {
      payplus_customer_uid: pickString(item, "customer_uid", "client_uid"),
      payplus_recurring_uid: recurringUid,
      customer_name: customerName,
      customer_email: pickString(
        item,
        "customer_email",
        "email",
        "client_email",
      ) ?? extractFromExtraInfo(item, ["email", "customer_email"]),
      customer_phone: pickString(
        item,
        "customer_phone",
        "phone",
        "mobile",
        "cellphone",
      ) ?? extractFromExtraInfo(item, ["phone", "customer_phone", "mobile"]),
      website_url: pickString(item, "website_url", "website", "site_url") ??
        extractFromExtraInfo(item, ["website", "website_url", "site"]),
      monthly_amount: amount,
      currency: pickString(item, "currency_code", "currency") ?? "ILS",
      billing_day: extractBillingDay(billingDaySource),
      next_billing_date: nextBillingDate,
      recurring_status: mapRecurringStatus(item),
      source: "payplus",
      raw_payplus_data: sanitizePayPlusData(item),
    },
    error: null,
  };
}

function mapRecurringStatus(item: PayPlusRecurringPayment): string {
  if (isActiveRecurringPayment(item)) return "active";

  const status = pickString(item, "status", "recurring_status");
  if (status) return status;

  return "inactive";
}

function pickString(
  obj: PayPlusRecurringPayment,
  ...keys: string[]
): string | null {
  for (const key of keys) {
    const value = obj[key];
    if (typeof value === "string" && value.trim()) return value.trim();
  }
  return null;
}

function pickNumber(
  obj: PayPlusRecurringPayment,
  ...keys: string[]
): number | null {
  for (const key of keys) {
    const value = obj[key];
    if (typeof value === "number" && Number.isFinite(value)) return value;
    if (typeof value === "string" && value.trim()) {
      const parsed = Number(value);
      if (Number.isFinite(parsed)) return parsed;
    }
  }
  return null;
}

function pickDateString(
  obj: PayPlusRecurringPayment,
  ...keys: string[]
): string | null {
  for (const key of keys) {
    const value = obj[key];
    if (typeof value !== "string" || !value.trim()) continue;

    const isoDate = normalizeDate(value.trim());
    if (isoDate) return isoDate;
  }
  return null;
}

function normalizeDate(value: string): string | null {
  if (/^\d{4}-\d{2}-\d{2}$/.test(value)) return value;

  const ddMmYyyy = value.match(/^(\d{2})\/(\d{2})\/(\d{4})$/);
  if (ddMmYyyy) {
    return `${ddMmYyyy[3]}-${ddMmYyyy[2]}-${ddMmYyyy[1]}`;
  }

  const parsed = new Date(value);
  if (Number.isNaN(parsed.getTime())) return null;

  return parsed.toISOString().slice(0, 10);
}

function extractBillingDay(dateStr: string | null): number | null {
  if (!dateStr) return null;
  const day = Number(dateStr.slice(8, 10));
  return day >= 1 && day <= 31 ? day : null;
}

function extractFromExtraInfo(
  item: PayPlusRecurringPayment,
  keys: string[],
): string | null {
  const extraInfo = item.extra_info;

  if (typeof extraInfo === "string" && extraInfo.trim()) {
    try {
      const parsed = JSON.parse(extraInfo) as Record<string, unknown>;
      for (const key of keys) {
        const value = parsed[key];
        if (typeof value === "string" && value.trim()) return value.trim();
      }
    } catch {
      return null;
    }
  }

  if (extraInfo && typeof extraInfo === "object" && !Array.isArray(extraInfo)) {
    const record = extraInfo as Record<string, unknown>;
    for (const key of keys) {
      const value = record[key];
      if (typeof value === "string" && value.trim()) return value.trim();
    }
  }

  return null;
}
